-- Generated from RENAPER-derived workbook: nombres_sexo_inferido_argentina - copia.xlsx
-- Contains only names with inferred sex M/F.

create table if not exists public.ar_name_inferred_sex (
  name_key text primary key,
  display_name text not null,
  inferred_sex text not null check (inferred_sex in ('m','f')),
  total_registros integer not null default 0,
  source text not null default 'renaper_derived',
  updated_at timestamptz not null default now()
);

comment on table public.ar_name_inferred_sex is
  'Catalogo de nombres argentinos con sexo inferido (m/f) para fallback por nombre.';
comment on column public.ar_name_inferred_sex.name_key is
  'Clave normalizada para matching (primer nombre, uppercase, sin acentos).';

create index if not exists idx_ar_name_inferred_sex_display_name
  on public.ar_name_inferred_sex (display_name);

on conflict (name_key) do update set
  display_name = excluded.display_name,
  inferred_sex = excluded.inferred_sex,
  total_registros = excluded.total_registros,
  source = excluded.source,
  updated_at = now();

